/**
 * β₁ proxy (cycle rank) and Laplacian construction from EffectiveGraphSnapshot.
 * Streaming λ₂ estimates are usually computed by a sparse solver service; pass those
 * numbers into `RollbackController` (see `rollback-controller.ts`).
 */

import type { EffectiveGraphSnapshot } from './types';

/**
 * Handles the gnosis component Count workflow.
 */
export function componentCount(g: EffectiveGraphSnapshot): number {
  const n = g.nodeCount;
  const parent = Array.from({ length: n }, (_, i) => i);
  function find(x: number): number {
    if (parent[x] !== x) parent[x] = find(parent[x]);
    return parent[x];
  }
  function union(a: number, b: number): void {
    const ra = find(a);
    const rb = find(b);
    if (ra !== rb) parent[ra] = rb;
  }
  for (const e of g.edges) {
    if (e.u >= 0 && e.u < n && e.v >= 0 && e.v < n) union(e.u, e.v);
  }
  const roots = new Set<number>();
  for (let i = 0; i < n; i++) roots.add(find(i));
  return roots.size;
}

/** β₁ = m − n + c (first Betti number). */
export function betti1Proxy(g: EffectiveGraphSnapshot): number {
  const n = g.nodeCount;
  const m = g.edges.length;
  const c = componentCount(g);
  return Math.max(0, m - n + c);
}

/** Weighted Laplacian (dense, for export to external eigen solvers). */
export function laplacianDense(g: EffectiveGraphSnapshot): number[][] {
  const n = g.nodeCount;
  const L: number[][] = Array.from({ length: n }, () => Array(n).fill(0));
  for (const e of g.edges) {
    const { u, v } = e;
    if (u < 0 || u >= n || v < 0 || v >= n || u === v) continue;
    const w = e.w ?? 1;
    L[u]![u]! += w;
    L[v]![v]! += w;
    L[u]![v]! -= w;
    L[v]![u]! -= w;
  }
  return L;
}
